/* ---------- reveal on scroll ---------- */
function useReveal() {
  const ref = useRef(null);
  const [shown, setShown] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    // следим только за ВЕРТИКАЛЬНЫМ появлением: широкие горизонтальные поля
    // не дают соседним панелям (лента шириной 300%, сдвинута вбок) считаться скрытыми
    const io = new IntersectionObserver(
      ([e]) => {
        if (e.isIntersecting) { setShown(true); io.unobserve(el); }
      },
      { threshold: 0, rootMargin: "0px 2000px 0px 2000px" }
    );
    // если карточка уже в пределах экрана по вертикали — показываем сразу, без мигания
    const r = el.getBoundingClientRect();
    if (r.top < window.innerHeight && r.bottom > 0) {
      setShown(true);
      io.disconnect();
      return () => {};
    }
    io.observe(el);
    const t = setTimeout(() => setShown(true), 600);  // страховка
    return () => { io.disconnect(); clearTimeout(t); };
  }, []);
  return [ref, shown];
}

