/* ============================================================
   LIST CARD
   ============================================================ */
function Card({ item, index, onOpen, qty = 0, onQuickAdd, onQuickRemove }) {
  const [ref, shown] = useReveal();
  const stop = (e) => e.stopPropagation();
  return (
    <article ref={ref} className={"card " + (item.big?"big ":"") + (shown?"in":"")}
      style={{ transitionDelay:(index%2)*80 + "ms" }} onClick={()=>onOpen(item)}>
      <div className={"media " + (item.kind!=="photo"?"coded":"")}>
        <Visual kind={item.kind} img={item.img} />
        {item.tag && <span className={"tag " + (item.tag==="new"?"new":"hit")}>{item.tag==="new"?"новинка":"хит"}</span>}
      </div>
      <div className="cardBody">
        <h3>{item.name}</h3>
        <div className="cardFoot">
          <span className="price">{fmt(item.price)}<i>TJS</i></span>
          {qty > 0 ? (
            <div className="stepper" onClick={stop}>
              <button className="stepBtn" aria-label="Убрать" onClick={(e)=>{stop(e); onQuickRemove(item);}}>
                <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M5 12h14"/></svg>
              </button>
              <span className="stepNum">{qty}</span>
              <button className="stepBtn add" aria-label="Добавить" onClick={(e)=>{stop(e); onQuickAdd(item);}}>
                <svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
              </button>
            </div>
          ) : (
            <button className="quickPlus" aria-label="Добавить в корзину" onClick={(e)=>{stop(e); onQuickAdd(item);}}>
              <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
            </button>
          )}
        </div>
      </div>
    </article>
  );
}

/* ============================================================
   DETAIL SHEET
   ============================================================ */
function Detail({ item, onClose, onAdd }) {
  const sizes = item.type==="drink" ? SIZES.drink : null;
  const addons = item.type==="drink" ? ADDONS.drink : ADDONS.food;
  const [size, setSize] = useState(sizes ? "m" : null);
  const [picked, setPicked] = useState([]);
  const [show, setShow] = useState(false);
  useEffect(()=>{ const t=setTimeout(()=>setShow(true),10); return ()=>clearTimeout(t); },[]);

  const toggle = (id) => setPicked(p => p.includes(id)?p.filter(x=>x!==id):[...p,id]);
  const sizeDelta = sizes ? sizes.find(s=>s.id===size).delta : 0;
  const addDelta = picked.reduce((s,id)=> s + addons.find(a=>a.id===id).price, 0);
  const total = item.price + sizeDelta + addDelta;

  const close = () => { setShow(false); setTimeout(onClose, 280); };
  const add = () => {
    const extras = picked.map(id=>addons.find(a=>a.id===id).name);
    onAdd({ ...item, finalPrice: total, sizeLabel: sizes?sizes.find(s=>s.id===size).label:null, extras });
    close();
  };

  return (
    <div className={"sheet " + (show?"sheetIn":"")}>
      <div className="sheetBackdrop" onClick={close} />
      <div className="sheetCard">
        <button className="closeBtn" onClick={close} aria-label="Закрыть">
          <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round"><path d="M6 6l12 12M18 6L6 18"/></svg>
        </button>
        <div className="sheetScroll">
          <div className={"detailMedia " + (item.kind!=="photo"?"coded":"")}>
            <Visual kind={item.kind} img={item.img} />
          </div>
          <h2 className="detailName">{item.name}</h2>
          <p className="detailDesc">{item.desc}</p>

          {sizes && (
            <div className="block">
              <h4>Размер</h4>
              <div className="sizeRow">
                {sizes.map(s=>(
                  <button key={s.id} className={"sizeBtn " + (size===s.id?"on":"")} onClick={()=>setSize(s.id)}>
                    <span>{s.label}</span>
                    <i>{s.delta===0?"базовый":(s.delta>0?"+"+fmt(s.delta):fmt(s.delta))}</i>
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="block">
            <h4>{item.type==="drink"?"Добавки":"Дополнительно"}</h4>
            <div className="addonList">
              {addons.map(a=>{
                const on = picked.includes(a.id);
                return (
                  <button key={a.id} className={"addon " + (on?"on":"")} onClick={()=>toggle(a.id)}>
                    <span className="addonName">{a.name}</span>
                    <span className="addonPrice">+{fmt(a.price)}</span>
                    <span className="addonCheck">
                      {on
                        ? <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round"><path d="M5 13l4 4L19 7"/></svg>
                        : <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>}
                    </span>
                  </button>
                );
              })}
            </div>
          </div>
          <div style={{height:96}} />
        </div>

        <div className="sheetBar">
          <button className="addBig" onClick={add}>
            <span>В корзину</span>
            <b>{fmt(total)} TJS</b>
          </button>
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   CART SHEET
   ============================================================ */
function CartSheet({ cart, onClose, onClear, onAddLine, onRemoveLine, onRemoveAll, lineKey, onCheckout }) {
  const [show, setShow] = useState(false);
  useEffect(()=>{ const t=setTimeout(()=>setShow(true),10); return ()=>clearTimeout(t); },[]);
  const close = () => { setShow(false); setTimeout(onClose,280); };

  // группируем одинаковые позиции
  const groups = [];
  const map = {};
  cart.forEach(i => {
    const k = lineKey(i);
    if (map[k] == null) { map[k] = groups.length; groups.push({ key: k, item: i, qty: 1 }); }
    else groups[map[k]].qty += 1;
  });
  const total = cart.reduce((s,i)=>s+i.finalPrice,0);
  const count = cart.length;

  return (
    <div className={"sheet " + (show?"sheetIn":"")}>
      <div className="sheetBackdrop" onClick={close} />
      <div className="sheetCard cartCard">
        <button className="closeBtn" onClick={close}>
          <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round"><path d="M6 6l12 12M18 6L6 18"/></svg>
        </button>
        <div className="sheetScroll">
          <h2 className="detailName" style={{marginTop:8}}>Корзина</h2>

          {count===0 && (
            <div className="cartEmpty">
              <div className="cartEmptyIcon">
                <svg viewBox="0 0 24 24" width="40" height="40" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M6 6h15l-1.5 9h-12z"/><path d="M6 6L5 3H3"/><circle cx="9" cy="20" r="1.4"/><circle cx="18" cy="20" r="1.4"/>
                </svg>
              </div>
              <p>Корзина пуста</p>
              <span>Добавь что-нибудь вкусное из меню</span>
            </div>
          )}

          {groups.map(g => (
            <div className="cartRow" key={g.key}>
              <div className="cartThumb"><Visual kind={g.item.kind} img={g.item.img} /></div>
              <div className="cartInfo">
                <strong>{g.item.name}</strong>
                <span>{[g.item.sizeLabel, ...(g.item.extras||[])].filter(Boolean).join(" · ")||"стандарт"}</span>
                <b className="cartLinePrice">{fmt(g.item.finalPrice * g.qty)} TJS</b>
              </div>
              <div className="cartRowRight">
                <button className="cartDel" aria-label="Удалить" onClick={()=>onRemoveAll(g.key)}>
                  <svg viewBox="0 0 24 24" width="17" height="17" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M3 6h18M8 6V4h8v2M6 6l1 14h10l1-14"/></svg>
                </button>
                <div className="stepper cartStepper">
                  <button className="stepBtn" aria-label="Меньше" onClick={()=>onRemoveLine(g.key)}>
                    <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M5 12h14"/></svg>
                  </button>
                  <span className="stepNum">{g.qty}</span>
                  <button className="stepBtn add" aria-label="Больше" onClick={()=>onAddLine(g.item)}>
                    <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
                  </button>
                </div>
              </div>
            </div>
          ))}

          {count>0 && (
            <div className="cartSummary">
              <div className="cartSummaryRow"><span>Позиций</span><span>{count}</span></div>
              <div className="cartSummaryRow total"><span>Итого</span><span>{fmt(total)} TJS</span></div>
            </div>
          )}

          <div style={{height:96}} />
        </div>
        <div className="sheetBar">
          <button className="addBig" disabled={!count} onClick={onCheckout}>
            <span>Оформить заказ</span><b>{fmt(total)} TJS</b>
          </button>
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   HERO SHOWCASE — крупная витрина продукта в начале вкладки
   Большой визуал во весь экран + название и цена внизу.
   Слот photoHero готов под реальное фото/видео продукта.
   ============================================================ */
function HeroShowcase({ item, onOpen, qty = 0, onQuickAdd, onQuickRemove }) {
  const stop = (e) => e.stopPropagation();
  return (
    <div className="heroShow" onClick={() => onOpen(item)}>
      <div className="heroShowMedia">
        <Visual kind={item.kind} img={item.img} />
      </div>
      <div className="heroShowShade" />
      {item.tag && <span className={"tag heroTag " + (item.tag === "new" ? "new" : "hit")}>{item.tag === "new" ? "новинка" : "хит"}</span>}
      <div className="heroShowInfo">
        <h2>{item.name}</h2>
        <div className="heroShowPrice">{fmt(item.price)} <i>TJS</i></div>
        {qty > 0 ? (
          <div className="stepper heroStepper" onClick={stop}>
            <button className="stepBtn" aria-label="Убрать" onClick={(e)=>{stop(e); onQuickRemove(item);}}>
              <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M5 12h14"/></svg>
            </button>
            <span className="stepNum">{qty}</span>
            <button className="stepBtn add" aria-label="Добавить" onClick={(e)=>{stop(e); onQuickAdd(item);}}>
              <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
            </button>
          </div>
        ) : (
          <button className="heroAddBtn" onClick={(e)=>{stop(e); onQuickAdd(item);}}>
            <svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
            В корзину
          </button>
        )}
      </div>
    </div>
  );
}

/* ============================================================
   PAGER — горизонтальный scroll-snap между вкладками.
   Вверху каждой вкладки большая витрина-герой, ниже сетка.
   ============================================================ */
// порядок вкладок после текущей, по кругу (для хвоста)
function tabsAfter(tabs, current) {
  const base = tabs.indexOf(current);
  const res = [];
  for (let k = 1; k < tabs.length; k++) res.push(tabs[(base + k) % tabs.length]);
  return res;
}

function Pager({ tabs, active, setActive, onOpen, cartCount, quickAdd, quickRemove, quickCount }) {
  const idx = Math.max(0, tabs.indexOf(active));
  const [dotTab, setDotTab] = useState(active);   // отдельная подсветка точек (не двигает ленту)
  const trackRef = useRef(null);
  const tabsRef = useRef(null);
  const lockRef = useRef(false);
  const byTab = tabs.map(t => MENU.filter(m => m.tab === t));

  const go = (i) => {
    const clamped = Math.min(tabs.length - 1, Math.max(0, i));
    const el = trackRef.current;
    if (!el) return;
    lockRef.current = true;
    el.scrollTo({ left: clamped * el.clientWidth, behavior: "smooth" });
    window.scrollTo({ top: 0, behavior: "smooth" });   // открываем раздел с начала — у героя
    setActive(tabs[clamped]);
    setTimeout(() => { lockRef.current = false; }, 420);
  };

  // зацикливание только на краях ленты: 4-й <-> 1-й
  const edgeTouch = useRef(null);
  const onTrackTouchStart = (e) => {
    const el = trackRef.current;
    if (!el) return;
    const atStart = el.scrollLeft <= 2;
    const atEnd = el.scrollLeft >= (el.scrollWidth - el.clientWidth - 2);
    edgeTouch.current = { x: e.touches[0].clientX, y: e.touches[0].clientY, atStart, atEnd };
  };
  const onTrackTouchEnd = (e) => {
    const t = edgeTouch.current;
    edgeTouch.current = null;
    if (!t) return;
    const dx = e.changedTouches[0].clientX - t.x;
    const dy = e.changedTouches[0].clientY - t.y;
    // только явный горизонтальный жест и только на самом краю
    if (Math.abs(dx) < 60 || Math.abs(dx) < Math.abs(dy) * 1.5) return;
    if (dx < 0 && t.atEnd) go(0);                 // с последнего влево -> первый
    else if (dx > 0 && t.atStart) go(tabs.length - 1);  // с первого вправо -> последний
  };

  const onScroll = () => {
    const el = trackRef.current;
    if (!el || lockRef.current) return;
    const i = Math.round(el.scrollLeft / el.clientWidth);
    if (tabs[i] && tabs[i] !== active) {
      setActive(tabs[i]);
      window.scrollTo({ top: 0, behavior: "smooth" });   // новый раздел открываем с начала — у героя
    }
  };

  // при смене активной вкладки (свайп/таб) синхронизируем подсветку точек
  useEffect(() => { setDotTab(active); }, [active]);

  // точки следят за вертикальным скроллом: какой data-block на экране — тот раздел и подсвечиваем
  useEffect(() => {
    let ticking = false;
    const handler = () => {
      if (lockRef.current || ticking) return;
      ticking = true;
      requestAnimationFrame(() => {
        ticking = false;
        const track = trackRef.current;
        if (!track) return;
        // работаем только с активной (видимой) страницей ленты
        const page = track.children[idx];
        if (!page) return;
        const line = window.innerHeight * 0.45;
        const blocks = page.querySelectorAll("[data-block]");
        let found = null;
        blocks.forEach(b => {
          const r = b.getBoundingClientRect();
          if (r.top <= line && r.bottom > line) found = b.getAttribute("data-block");
        });
        if (found && found !== dotTab) setDotTab(found);
      });
    };
    window.addEventListener("scroll", handler, { passive: true });
    return () => window.removeEventListener("scroll", handler);
  }, [idx, dotTab]);

  // центрируем активный таб в ленте табов (следует за подсветкой dotTab)
  useEffect(() => {
    const el = tabsRef.current;
    if (!el) return;
    const di = Math.max(0, tabs.indexOf(dotTab));
    const btn = el.children[di];
    if (btn) el.scrollTo({ left: btn.offsetLeft - el.clientWidth / 2 + btn.clientWidth / 2, behavior: "smooth" });
  }, [dotTab, tabs]);

  // если active сменили извне (таб/точка) — двигаем ленту
  useEffect(() => {
    const el = trackRef.current;
    if (!el) return;
    if (Math.round(el.scrollLeft / el.clientWidth) !== idx) {
      lockRef.current = true;
      el.scrollTo({ left: idx * el.clientWidth, behavior: "smooth" });
      setTimeout(() => { lockRef.current = false; }, 420);
    }
  }, [idx]);

  return (
    <div className="pager">
      <nav className="tabs stuck" ref={tabsRef}>
        {tabs.map((t, i) => (
          <button key={t} className={"tab " + (dotTab === t ? "on" : "")} onClick={() => go(i)}>{t}</button>
        ))}
      </nav>

      <div className="track" ref={trackRef} onScroll={onScroll} onTouchStart={onTrackTouchStart} onTouchEnd={onTrackTouchEnd}>
        {byTab.map((sections, i) => {
          const tab = tabs[i];
          const allItems = sections.flatMap(sec => sec.items);
          const hero = allItems.find(it => it.hero);
          return (
            <div className="page" key={tab}>
              {hero && <HeroShowcase item={hero} onOpen={onOpen} qty={quickCount(hero.id)} onQuickAdd={quickAdd} onQuickRemove={quickRemove} />}
              {sections.length === 0 && (
                <div className="emptyTab">
                  <div className="emptyIcon">
                    <svg viewBox="0 0 24 24" width="34" height="34" fill="none" stroke="currentColor" strokeWidth="1.5">
                      <circle cx="11" cy="11" r="7" /><path d="M21 21l-4.3-4.3" />
                    </svg>
                  </div>
                  <p>Раздел «{tab}» скоро наполним</p>
                  <span>Листай влево-вправо, чтобы переключать категории</span>
                </div>
              )}
              <div className="pageBody">
                {sections.length > 1 && (
                  <div className="subChips">
                    {sections.map(sec => (
                      <button key={"chip-" + sec.cat} className="subChip"
                        onClick={(e) => {
                          const card = e.currentTarget.closest(".page");
                          const target = card && card.querySelector('[data-sec="' + sec.cat + '"]');
                          if (target) {
                            const top = target.getBoundingClientRect().top + window.scrollY - 70;
                            window.scrollTo({ top, behavior: "smooth" });
                          }
                        }}>
                        {sec.cat}
                      </button>
                    ))}
                  </div>
                )}
                <div data-block={tab}>
                  {sections.map(sec => {
                    const items = sec.items.filter(it => !it.hero);
                    if (!items.length) return null;
                    return (
                      <section className="section" key={sec.cat} data-sec={sec.cat}>
                        <h2 className="secTitle">{sec.cat}</h2>
                        <div className="grid">
                          {items.map((it, j) => (
                            <Card key={it.id} item={{ ...it, big: j % 3 === 0 }} index={j} onOpen={onOpen} qty={quickCount(it.id)} onQuickAdd={quickAdd} onQuickRemove={quickRemove} />
                          ))}
                        </div>
                      </section>
                    );
                  })}
                </div>

                {tabsAfter(tabs, tab).map(t => {
                  const secs = MENU.filter(m => m.tab === t);
                  const cards = secs.flatMap(sec => sec.items);   // включая бывшего героя — обычной карточкой
                  if (!cards.length) return null;
                  return (
                    <div data-block={t} key={"more-" + t} className="moreBlock">
                      <h2 className="secTitle moreTitle">{t}</h2>
                      <div className="grid">
                        {cards.map((it, j) => (
                          <Card key={"m" + it.id} item={{ ...it, big: j % 3 === 0, hero: false }} index={j} onOpen={onOpen} qty={quickCount(it.id)} onQuickAdd={quickAdd} onQuickRemove={quickRemove} />
                        ))}
                      </div>
                    </div>
                  );
                })}

                <p className="footNote">Яккасарой Family · это весь ассортимент</p>
              </div>
            </div>
          );
        })}
      </div>

      <div className={"dots " + (cartCount ? "dotsHidden" : "")}>
        {tabs.map((t, i) => (
          <span key={t} className={"dot " + (t === dotTab ? "on" : "")} onClick={() => go(i)} />
        ))}
      </div>
    </div>
  );
}

/* ============================================================
   APP
   ============================================================ */
function Checkout({ cart, onClose, onDone }) {
  const [show, setShow] = useState(false);
  useEffect(()=>{ const t=setTimeout(()=>setShow(true),10); return ()=>clearTimeout(t); },[]);
  const close = () => { setShow(false); setTimeout(onClose,280); };

  const total = cart.reduce((s,i)=>s+i.finalPrice,0);
  const count = cart.length;
  const [table, setTable] = useState("12");      // номер стола (как будто из QR)
  const [editTable, setEditTable] = useState(false);
  const [pay, setPay] = useState("cash");          // cash | qr
  const [comment, setComment] = useState("");
  const [placed, setPlaced] = useState(false);
  const orderNo = useRef(Math.floor(100 + Math.random()*900));

  const confirm = () => { setPlaced(true); };

  return (
    <div className={"sheet " + (show?"sheetIn":"")}>
      <div className="sheetBackdrop" onClick={close} />
      <div className="sheetCard cartCard">
        {!placed ? (
          <>
            <button className="closeBtn" onClick={close}>
              <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round"><path d="M6 6l12 12M18 6L6 18"/></svg>
            </button>
            <div className="sheetScroll">
              <h2 className="detailName" style={{marginTop:8}}>Оформление</h2>

              {/* стол из QR */}
              <div className="coBlock">
                <div className="coLabel">Стол</div>
                {editTable ? (
                  <div className="coTableEdit">
                    <input className="coInput" value={table} onChange={e=>setTable(e.target.value)}
                      inputMode="numeric" autoFocus />
                    <button className="coMiniBtn" onClick={()=>setEditTable(false)}>Готово</button>
                  </div>
                ) : (
                  <div className="coTableShow">
                    <span className="coTableNum">Стол №{table || "—"}</span>
                    <span className="coTableHint">определён по QR-коду</span>
                    <button className="coChange" onClick={()=>setEditTable(true)}>Изменить</button>
                  </div>
                )}
              </div>

              {/* способ оплаты */}
              <div className="coBlock">
                <div className="coLabel">Оплата</div>
                <button className={"payOpt " + (pay==="cash"?"on":"")} onClick={()=>setPay("cash")}>
                  <span className="payIcon">
                    <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" strokeWidth="1.8"><rect x="2" y="6" width="20" height="12" rx="2"/><circle cx="12" cy="12" r="2.5"/></svg>
                  </span>
                  <span className="payTxt"><strong>Наличными</strong><span>Оплата официанту</span></span>
                  <span className="payDot" />
                </button>
                <button className={"payOpt " + (pay==="qr"?"on":"")} onClick={()=>setPay("qr")}>
                  <span className="payIcon">
                    <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" strokeWidth="1.8"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/><path d="M14 14h3v3M21 14v7M17 21h4"/></svg>
                  </span>
                  <span className="payTxt"><strong>По QR · Ягона</strong><span>Сканируй и оплати в приложении</span></span>
                  <span className="payDot" />
                </button>

                {pay==="qr" && (
                  <div className="qrPay">
                    <div className="qrBox">
                      <svg viewBox="0 0 100 100" width="150" height="150" fill="#15151b">
                        <rect x="0" y="0" width="30" height="30"/><rect x="8" y="8" width="14" height="14" fill="#fff"/>
                        <rect x="70" y="0" width="30" height="30"/><rect x="78" y="8" width="14" height="14" fill="#fff"/>
                        <rect x="0" y="70" width="30" height="30"/><rect x="8" y="78" width="14" height="14" fill="#fff"/>
                        <rect x="40" y="0" width="8" height="8"/><rect x="52" y="0" width="8" height="8"/>
                        <rect x="40" y="14" width="8" height="8"/><rect x="60" y="20" width="8" height="8"/>
                        <rect x="0" y="40" width="8" height="8"/><rect x="14" y="40" width="8" height="8"/>
                        <rect x="40" y="40" width="8" height="8"/><rect x="52" y="48" width="8" height="8"/>
                        <rect x="68" y="40" width="8" height="8"/><rect x="84" y="40" width="8" height="8"/>
                        <rect x="40" y="60" width="8" height="8"/><rect x="60" y="60" width="8" height="8"/>
                        <rect x="76" y="60" width="8" height="8"/><rect x="40" y="76" width="8" height="8"/>
                        <rect x="60" y="76" width="8" height="8"/><rect x="76" y="76" width="8" height="8"/><rect x="88" y="88" width="8" height="8"/>
                      </svg>
                    </div>
                    <p className="qrHint">Отсканируйте код в приложении <strong>Ягона</strong></p>
                  </div>
                )}
              </div>

              {/* комментарий */}
              <div className="coBlock">
                <div className="coLabel">Комментарий к заказу</div>
                <textarea className="coTextarea" placeholder="Например: без сахара, погорячее…"
                  value={comment} onChange={e=>setComment(e.target.value)} rows={2} />
              </div>

              {/* мини-сводка */}
              <div className="cartSummary">
                <div className="cartSummaryRow"><span>Позиций</span><span>{count}</span></div>
                <div className="cartSummaryRow total"><span>Итого</span><span>{fmt(total)} TJS</span></div>
              </div>
              <div style={{height:96}} />
            </div>
            <div className="sheetBar">
              <button className="addBig" disabled={!count || !table} onClick={confirm}>
                <span>Подтвердить заказ</span><b>{fmt(total)} TJS</b>
              </button>
            </div>
          </>
        ) : (
          <div className="orderDone">
            <div className="doneCheck">
              <svg viewBox="0 0 24 24" width="44" height="44" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5"/></svg>
            </div>
            <h2>Заказ принят!</h2>
            <p className="doneNo">Заказ №{orderNo.current}</p>
            <p className="doneTxt">Передан на кухню. Стол №{table}.<br/>Оплата: {pay==="cash" ? "наличными официанту" : "по QR · Ягона"}.</p>
            <div className="doneEta">Готовим · ~10–15 мин</div>
            <button className="addBig doneBtn" onClick={onDone}>
              <span>Готово</span>
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default function App() {
  const [active, setActive] = useState("кофе");
  const [cart, setCart] = useState([]);
  const [detail, setDetail] = useState(null);
  const [cartOpen, setCartOpen] = useState(false);
  const [checkout, setCheckout] = useState(false);
  const [bump, setBump] = useState(false);

  const addToCart=(it)=>{ setCart(c=>[...c,it]); setBump(true); setTimeout(()=>setBump(false),400); };
  const total=useMemo(()=>cart.reduce((s,i)=>s+i.finalPrice,0),[cart]);

  // быстрое добавление из карточки (средний размер, без добавок) — помечаем quick:item.id
  const quickAdd=(it)=>{
    setCart(c=>[...c, { ...it, finalPrice: it.price, sizeLabel: null, extras: [], quick: it.id }]);
    setBump(true); setTimeout(()=>setBump(false),400);
  };
  const quickRemove=(it)=>{
    setCart(c=>{ const i=c.map(x=>x.quick).lastIndexOf(it.id); if(i<0) return c; const n=[...c]; n.splice(i,1); return n; });
  };
  const quickCount=(id)=>cart.reduce((n,i)=>n+(i.quick===id?1:0),0);

  // подпись позиции для группировки (одинаковые = name+size+addons)
  const lineKey=(i)=>i.name + "|" + (i.sizeLabel||"") + "|" + ((i.extras||[]).join(","));
  const addLine=(line)=>{ setCart(c=>[...c, { ...line }]); };
  const removeLine=(key)=>{
    setCart(c=>{ const idx=c.map(lineKey).lastIndexOf(key); if(idx<0) return c; const n=[...c]; n.splice(idx,1); return n; });
  };
  const removeAll=(key)=>{ setCart(c=>c.filter(i=>lineKey(i)!==key)); };

  return (
    <div className="app">
      <Styles/>
      <header className="hero">
        <div className="heroGlow"/>
        <div className="brandRow">
          <div className="logo">
            <svg viewBox="0 0 40 40" width="24" height="24">
              <path d="M26 12a10 10 0 1 0 0 16 8 8 0 1 1 0-16z" fill="#15151b"/>
            </svg>
          </div>
          <div className="brandTxt"><strong>ЯККАСАРОЙ</strong><span>Family · откроемся в 9:30</span></div>
          <button className="profile" aria-label="Профиль">
            <svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" strokeWidth="1.8"><circle cx="12" cy="8" r="4"/><path d="M4 21c0-4 4-6 8-6s8 2 8 6"/></svg>
          </button>
        </div>
      </header>

      <Pager tabs={TABS} active={active} setActive={setActive} onOpen={setDetail} cartCount={cart.length} quickAdd={quickAdd} quickRemove={quickRemove} quickCount={quickCount} />

      <div className={"cartBar " + (cart.length?"show ":"") + (bump?"bump":"")} onClick={()=>setCartOpen(true)}>
        <div className="cartCountBadge">{cart.length}</div>
        <span className="cartBarLabel">Корзина</span>
        <span className="cartBarTotal">{fmt(total)} TJS</span>
      </div>

      {detail && <Detail item={detail} onClose={()=>setDetail(null)} onAdd={addToCart}/>}
      {checkout && <Checkout cart={cart} onClose={()=>setCheckout(false)} onDone={()=>{ setCart([]); setCheckout(false); }}/>}
      {cartOpen && <CartSheet cart={cart} onClose={()=>setCartOpen(false)} onClear={()=>{setCart([]); setCartOpen(false);}} onAddLine={addLine} onRemoveLine={removeLine} onRemoveAll={removeAll} lineKey={lineKey} onCheckout={()=>{ setCartOpen(false); setCheckout(true); }}/>}
    </div>
  );
}

/* ============================================================
   STYLES
   ============================================================ */
function Styles(){return(<style>{`
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');
*{box-sizing:border-box;touch-action:pan-x pan-y;margin:0;padding:0;-webkit-tap-highlight-color:transparent;}
html{scroll-behavior:smooth;}
@media (prefers-reduced-motion:reduce){html,.track{scroll-behavior:auto;}}
.app{
  --bg:#0d1f33;--bg2:rgba(255,255,255,0.06);--card:rgba(28,34,44,0.55);--ink:#f5f8fa;--mut:#a8b2bd;
  --accent:#f4c430;--accent2:#e0ab10;--blue:#5b8def;--line:rgba(255,255,255,0.10);
  --glassBorder:rgba(255,255,255,0.14);--glassHi:rgba(255,255,255,0.22);--solid:#141a24;
  --grad:linear-gradient(180deg,rgba(255,255,255,0.6) 0%,rgba(255,255,255,0.14) 46%,rgba(255,255,255,0) 50%,rgba(255,255,255,0.05) 100%),linear-gradient(180deg,#ffd95e 0%,#f4c430 46%,#e0ab10 100%);
  background:linear-gradient(160deg,#0b1f3a 0%,#0e2a44 22%,#102a2e 50%,#0d1f33 78%,#0a1526 100%);
  background-attachment:fixed;
  color:var(--ink);font-family:-apple-system,BlinkMacSystemFont,'SF Pro Display','SF Pro Text','Inter',system-ui,sans-serif;
  -webkit-font-smoothing:antialiased;letter-spacing:-0.01em;
  min-height:100vh;max-width:540px;margin:0 auto;position:relative;overflow-x:clip;overflow-y:visible;padding-bottom:120px;
  touch-action:pan-x pan-y;
}
.hero{position:relative;padding:14px 18px 12px;overflow:hidden;border-bottom:1px solid var(--glassBorder);background:rgba(11,31,58,0.35);backdrop-filter:blur(20px) saturate(160%);-webkit-backdrop-filter:blur(20px) saturate(160%);}
.heroGlow{position:absolute;top:-130px;right:-90px;width:320px;height:320px;
  background:radial-gradient(circle,rgba(244,196,48,.26),transparent 60%);filter:blur(18px);
  animation:floatGlow 9s ease-in-out infinite;}
@keyframes floatGlow{0%,100%{transform:translate(0,0)}50%{transform:translate(-28px,28px)}}
.brandRow{display:flex;align-items:center;gap:12px;position:relative;z-index:2;}
.logo{width:40px;height:40px;border-radius:12px;display:grid;place-items:center;flex:0 0 auto;background:linear-gradient(135deg,#ffd95e,#e0ab10);box-shadow:0 4px 14px rgba(244,196,48,.5),inset 0 1px 0 rgba(255,255,255,0.45);animation:pop .7s cubic-bezier(.2,1.4,.4,1) both;}
.brandTxt{display:flex;flex-direction:column;line-height:1.25;}
.brandTxt strong{font-family:inherit;letter-spacing:-0.02em;font-weight:800;font-size:15px;letter-spacing:.5px;}
.brandTxt span{font-size:11.5px;color:var(--mut);}
.profile{margin-left:auto;width:42px;height:42px;border-radius:50%;border:1px solid var(--line);
  background:var(--bg2);color:var(--ink);display:grid;place-items:center;cursor:pointer;transition:.2s;}
.profile:hover{border-color:#3a3a46;transform:scale(1.05);}
@keyframes rise{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:none}}
@keyframes pop{from{opacity:0;transform:scale(.4) rotate(-30deg)}to{opacity:1;transform:none}}
.tabs{position:sticky;top:0;z-index:50;display:flex;gap:8px;padding:13px 16px;overflow-x:auto;
  scrollbar-width:none;transition:.3s;
  background:rgba(11,31,58,.55);backdrop-filter:blur(16px) saturate(140%);-webkit-backdrop-filter:blur(16px) saturate(140%);}
.tabs::-webkit-scrollbar{display:none;}
.stuck{background:rgba(11,31,58,.7);border-bottom:1px solid var(--line);}
.tab{flex:0 0 auto;padding:9px 18px;border-radius:100px;border:1px solid transparent;background:transparent;
  color:var(--mut);font:inherit;font-weight:600;font-size:14px;cursor:pointer;transition:.25s;}
.tab:hover{color:var(--ink);}
.tab.on{background:var(--bg2);color:var(--ink);border-color:var(--glassBorder);box-shadow:inset 0 1px 0 var(--glassHi);}
.menu{padding:6px 16px 0;}
.section{margin-bottom:28px;}
.secTitle{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:19px;margin:16px 4px 12px;text-transform:lowercase;}
.moreTitle{margin-top:32px;padding-top:24px;border-top:1px solid var(--line);}
.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px;}
.card{background:var(--card);border-radius:22px;overflow:hidden;cursor:pointer;border:1px solid var(--glassBorder);backdrop-filter:blur(20px) saturate(160%);-webkit-backdrop-filter:blur(20px) saturate(160%);box-shadow:inset 0 1px 0 var(--glassHi),0 8px 24px rgba(0,0,0,.35);
  display:flex;flex-direction:column;opacity:0;transform:translateY(26px) scale(.97);
  transition:opacity .55s,transform .55s,box-shadow .3s,border-color .3s;will-change:transform,opacity;}
.card.in{opacity:1;transform:none;}
.card:hover{transform:translateY(-5px);box-shadow:inset 0 1px 0 var(--glassHi),0 18px 40px -14px rgba(0,0,0,.6);border-color:var(--glassHi);}
.card:active{transform:scale(.98);}
.big{grid-column:1/-1;}
.media{position:relative;aspect-ratio:1/1;overflow:hidden;background:radial-gradient(circle at 50% 32%,#23232c,#141419);}
.big .media{aspect-ratio:16/11;}
.coded{background:radial-gradient(circle at 50% 30%,#2a2a34,#131318);}
.card:hover .art{transform:scale(1.06);}
.art{transition:transform .5s cubic-bezier(.2,.8,.3,1);}
.tag{position:absolute;top:12px;left:12px;z-index:5;padding:5px 11px;border-radius:100px;font-size:11px;
  font-weight:700;text-transform:uppercase;letter-spacing:.5px;}
.tag.hit{background:var(--accent);color:#15151b;}
.tag.new{background:var(--blue);color:#fff;}
.cardBody{padding:13px 14px 14px;display:flex;flex-direction:column;gap:10px;flex:1;}
.cardBody h3{font-size:14.5px;font-weight:700;line-height:1.25;}
.big .cardBody h3{font-size:17px;}
.cardFoot{display:flex;align-items:center;justify-content:space-between;margin-top:auto;}
.price{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:18px;}
.price i{font-style:normal;color:var(--mut);font-size:12px;margin-left:4px;}
.chev{color:var(--mut);}
/* быстрый плюсик и счётчик в карточке */
.quickPlus{width:40px;height:40px;border-radius:13px;border:1px solid rgba(255,255,255,0.5);cursor:pointer;flex:0 0 auto;
  background:var(--grad);color:#15151b;display:grid;place-items:center;transition:.18s;}
.quickPlus:hover{transform:scale(1.08);}
.quickPlus:active{transform:scale(.92);}
.stepper{display:flex;align-items:center;gap:4px;background:linear-gradient(180deg,rgba(255,255,255,.10),rgba(255,255,255,0) 60%),var(--bg2);border:1px solid var(--glassBorder);backdrop-filter:blur(10px);-webkit-backdrop-filter:blur(10px);box-shadow:inset 0 1px 0 var(--glassHi);
  border-radius:100px;padding:3px;flex:0 0 auto;}
.stepBtn{width:34px;height:34px;border-radius:50%;border:none;cursor:pointer;display:grid;place-items:center;
  background:transparent;color:var(--ink);transition:.18s;}
.stepBtn:hover{background:#2a2a32;}
.stepBtn:active{transform:scale(.9);}
.stepBtn.add{background:var(--grad);color:#15151b;border:1px solid rgba(255,255,255,0.5);box-shadow:0 4px 12px -2px rgba(244,196,48,.5);}
.stepBtn.add:hover{filter:brightness(1.06);}
.stepNum{min-width:22px;text-align:center;font-weight:700;font-size:15px;color:var(--ink);}
.dishPhoto{width:100%;height:100%;object-fit:cover;object-position:center 38%;display:block;}
/* в карточках сетки показываем фото целиком по центру */
.media .dishPhoto{object-fit:cover;object-position:center 40%;background:#efe7da;}
.photoSlot{position:absolute;inset:0;display:grid;place-items:center;color:#41414c;}
.photoSlot::after{content:"";position:absolute;inset:0;
  background:linear-gradient(120deg,transparent 30%,rgba(255,255,255,.045) 50%,transparent 70%);
  background-size:200% 100%;animation:shine 3.2s linear infinite;}
@keyframes shine{from{background-position:200% 0}to{background-position:-100% 0}}
.art{position:absolute;inset:0;display:grid;place-items:center;}
.gshadow,.bshadow{position:absolute;bottom:15%;width:55%;height:13px;left:22.5%;
  background:radial-gradient(ellipse,rgba(0,0,0,.5),transparent 70%);filter:blur(4px);}
.glass{position:relative;width:72px;height:116px;border-radius:8px 8px 14px 14px;
  background:linear-gradient(180deg,rgba(255,255,255,.10),rgba(255,255,255,.03));
  border:1.5px solid rgba(255,255,255,.18);overflow:hidden;box-shadow:inset 0 0 18px rgba(255,255,255,.08);}
.glass.tall{height:128px;}
.milk{position:absolute;inset:0;top:38%;background:linear-gradient(180deg,#f3ead9,#e9ddc4);}
.coffee{position:absolute;inset:0;top:8%;height:60%;
  background:linear-gradient(180deg,#6b4a2f,#b07b4e 55%,transparent);mix-blend-mode:multiply;opacity:.92;
  animation:swirl 4s ease-in-out infinite alternate;}
@keyframes swirl{from{transform:translateY(-3px) skewX(-2deg)}to{transform:translateY(4px) skewX(3deg)}}
.pour{position:absolute;top:4px;left:50%;width:4px;height:46px;transform:translateX(-50%);
  background:linear-gradient(180deg,#5a3a22,#8a5a34);border-radius:3px;animation:pour 2.4s ease-in-out infinite;}
@keyframes pour{0%,100%{opacity:0;transform:translateX(-50%) scaleY(.3)}30%,70%{opacity:.9;transform:translateX(-50%) scaleY(1)}}
.ice{position:absolute;width:19px;height:17px;border-radius:5px;
  background:linear-gradient(135deg,rgba(255,255,255,.5),rgba(255,255,255,.12));
  border:1px solid rgba(255,255,255,.4);}
.i1{top:24%;left:14%;animation:bob 3s ease-in-out infinite;}
.i2{top:40%;right:16%;transform:rotate(20deg);animation:bob 3.6s .4s ease-in-out infinite;}
.i3{top:55%;left:30%;transform:rotate(-12deg);animation:bob 3.2s .8s ease-in-out infinite;}
@keyframes bob{0%,100%{transform:translateY(0) rotate(0)}50%{transform:translateY(-4px) rotate(8deg)}}
.caramelPour{background:linear-gradient(180deg,#a86a25,#d89a48);}
.caramelMilk{background:linear-gradient(180deg,#f6ecd6,#ecd9b4);}
.caramelCoffee{background:linear-gradient(180deg,#7a4a1e,#c98a40 55%,transparent);}
.drizzle{position:absolute;top:6%;left:8%;right:8%;height:48%;
  background:repeating-linear-gradient(115deg,transparent 0 9px,rgba(180,110,40,.5) 9px 12px);
  mix-blend-mode:overlay;animation:swirl 5s ease-in-out infinite alternate;}
.matchaScene .glass{width:72px;}
.mMilk{position:absolute;inset:0;top:30%;background:linear-gradient(180deg,#f4f1e6,#e7e2cf);}
.mBlob{position:absolute;inset:0;background:radial-gradient(circle at 50% 30%,#9cc44d,#6fa12e 45%,transparent 70%);
  opacity:.9;animation:blob 5s ease-in-out infinite alternate;}
@keyframes blob{from{transform:translateY(-4px) scale(1)}to{transform:translateY(6px) scale(1.08)}}
.bead{position:absolute;border-radius:50%;background:radial-gradient(circle at 30% 30%,#fff,#cfe39a);}
.bd1{width:11px;height:11px;bottom:24%;left:24%;animation:bob 4s ease-in-out infinite;}
.bd2{width:8px;height:8px;bottom:30%;right:26%;animation:bob 3.4s .6s ease-in-out infinite;}
.mangoBottom{position:absolute;inset:0;top:72%;background:linear-gradient(180deg,#f6b733,#e89c1c);}
.mangoMilk{position:absolute;inset:0;top:34%;bottom:14%;background:linear-gradient(180deg,#f7f3e8,#efe7d2);}
.mangoTop{position:absolute;inset:0;bottom:66%;background:radial-gradient(circle at 50% 40%,#a6cf57,#7aa835);
  animation:blob 5s ease-in-out infinite alternate;}
.berryFoam{position:absolute;top:3%;left:5%;right:5%;height:24px;border-radius:10px;
  background:linear-gradient(180deg,#e7679a,#d34d83);box-shadow:0 2px 8px rgba(211,77,131,.4);}
.hotScene .cup{position:relative;width:84px;height:72px;border-radius:0 0 40px 40px;
  background:linear-gradient(180deg,#3a2a1e,#241710);border:2px solid #4a382a;box-shadow:inset 0 -8px 18px rgba(0,0,0,.5);}
.cupRim{position:absolute;top:-1px;left:-1px;right:-1px;height:14px;border-radius:50%;background:#1c120c;border:2px solid #4a382a;}
.cupLiq{position:absolute;top:5px;left:8px;right:8px;height:12px;border-radius:50%;
  background:radial-gradient(ellipse,#c49a6c,#7a5430);animation:ripple 3s ease-in-out infinite;}
@keyframes ripple{0%,100%{transform:scaleX(1)}50%{transform:scaleX(.92)}}
.hotScene .cup::after{content:"";position:absolute;right:-21px;top:13px;width:21px;height:33px;
  border:5px solid #4a382a;border-left:none;border-radius:0 22px 22px 0;}
.saucer{position:absolute;bottom:19%;width:118px;height:14px;border-radius:50%;
  background:linear-gradient(180deg,#33251a,#1d130c);box-shadow:0 6px 14px rgba(0,0,0,.5);}
.steam{position:absolute;top:13%;width:7px;height:40px;border-radius:8px;
  background:linear-gradient(180deg,rgba(255,255,255,.55),transparent);filter:blur(2px);opacity:0;}
.st1{left:42%;animation:steam 3s ease-in-out infinite;}
.st2{left:50%;animation:steam 3s .7s ease-in-out infinite;}
.st3{left:58%;animation:steam 3s 1.3s ease-in-out infinite;}
@keyframes steam{0%{opacity:0;transform:translateY(8px) scaleY(.6)}40%{opacity:.7}100%{opacity:0;transform:translateY(-26px) scaleY(1.3) translateX(6px)}}
.bowlScene .bowl{position:relative;width:118px;height:60px;border-radius:0 0 70px 70px;
  background:linear-gradient(180deg,#d8c9a8,#b89a6e);overflow:hidden;border:2px solid #c9b48c;
  animation:breathe 5s ease-in-out infinite;}
@keyframes breathe{0%,100%{transform:scale(1)}50%{transform:scale(1.04)}}
.bowlFill{position:absolute;top:0;left:0;right:0;height:60%;background:radial-gradient(ellipse at 50% 0,#e8dcc0,#d2c096);}
.top{position:absolute;border-radius:50%;}
.t1{width:25px;height:13px;top:6px;left:18px;background:radial-gradient(circle,#e85d3b,#b8401f);}
.t2{width:19px;height:10px;top:4px;right:22px;background:radial-gradient(circle,#8fbf3f,#5e8a26);}
.t3{width:15px;height:9px;top:13px;left:48px;background:radial-gradient(circle,#f2d24a,#c9a51f);}
.bowlGloss{position:absolute;top:0;left:10%;width:30%;height:40%;
  background:linear-gradient(120deg,rgba(255,255,255,.4),transparent);border-radius:50%;}
.cartBar{position:fixed;left:50%;bottom:24px;transform:translateX(-50%) translateY(120px);
  width:min(480px,calc(100% - 32px));z-index:40;background:var(--grad);color:#15151b;border-radius:18px;border:1px solid rgba(255,255,255,0.5);
  padding:16px 20px;display:flex;align-items:center;gap:14px;cursor:pointer;
  box-shadow:inset 0 2px 3px rgba(255,255,255,0.65),inset 0 -3px 7px rgba(150,100,0,0.3),0 14px 36px -10px rgba(244,196,48,.5),0 4px 12px rgba(0,0,0,0.22);opacity:0;
  transition:transform .45s cubic-bezier(.2,1.2,.3,1),opacity .35s;}
.cartBar.show{transform:translateX(-50%) translateY(0);opacity:1;}
.cartBar:active{box-shadow:inset 0 3px 8px rgba(0,0,0,.22),0 0 26px rgba(244,196,48,.6);}
.cartBar.bump{animation:bumpA .4s ease;}
@keyframes bumpA{0%,100%{transform:translateX(-50%) translateY(0) scale(1)}40%{transform:translateX(-50%) translateY(0) scale(1.04)}}
.cartCountBadge{width:30px;height:30px;border-radius:10px;background:rgba(255,255,255,.22);display:grid;place-items:center;font-weight:800;}
.cartBarLabel{font-weight:700;font-size:15px;}
.cartBarTotal{margin-left:auto;font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:17px;}
.footNote{color:#4d4d57;font-size:12px;text-align:center;padding:8px 20px 30px;}
.sheet{position:fixed;inset:0;z-index:60;}
.sheetBackdrop{position:absolute;inset:0;background:rgba(0,0,0,0);transition:background .3s;}
.sheetIn .sheetBackdrop{background:rgba(0,0,0,.6);}
.sheetCard{position:absolute;left:50%;bottom:0;transform:translateX(-50%) translateY(100%);
  width:100%;max-width:540px;max-height:94vh;background:rgba(16,28,44,0.82);backdrop-filter:blur(34px) saturate(170%);-webkit-backdrop-filter:blur(34px) saturate(170%);border-radius:26px 26px 0 0;
  display:flex;flex-direction:column;transition:transform .35s cubic-bezier(.2,.9,.3,1);
  border:1px solid var(--glassBorder);border-bottom:none;box-shadow:inset 0 1px 0 var(--glassHi);}
.sheetIn .sheetCard{transform:translateX(-50%) translateY(0);}
.closeBtn{position:absolute;top:14px;right:14px;z-index:5;width:40px;height:40px;border-radius:50%;
  border:1px solid rgba(255,255,255,0.4);background:linear-gradient(180deg,rgba(255,255,255,.24),rgba(255,255,255,0) 50%),rgba(40,40,48,.7);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);color:var(--ink);display:grid;place-items:center;cursor:pointer;transition:.2s;}
.closeBtn:hover{background:rgba(60,60,70,.95);transform:scale(1.06);}
.sheetScroll{overflow-y:auto;padding:0 20px;}
.detailMedia{position:relative;height:240px;margin:0 -20px;overflow:hidden;
  background:radial-gradient(circle at 50% 35%,#23232c,#141419);}
.detailMedia.coded{background:radial-gradient(circle at 50% 32%,#2b2b36,#131318);}
.detailMedia .art{transform:scale(1.5);}
.detailName{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:24px;margin:20px 0 8px;line-height:1.15;}
.detailDesc{color:var(--mut);font-size:14px;line-height:1.5;margin-bottom:18px;}
.block{margin-bottom:22px;}
.block h4{font-size:15px;font-weight:700;margin-bottom:10px;}
.sizeRow{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;}
.sizeBtn{display:flex;flex-direction:column;gap:3px;align-items:center;padding:12px 6px;border-radius:14px;
  border:1.5px solid var(--glassBorder);background:linear-gradient(180deg,rgba(255,255,255,.08),rgba(255,255,255,0) 55%),var(--bg2);color:var(--ink);cursor:pointer;transition:.2s;font:inherit;}
.sizeBtn span{font-weight:700;font-size:14px;}
.sizeBtn i{font-style:normal;color:var(--mut);font-size:11px;}
.sizeBtn.on{border-color:var(--accent);background:rgba(244,196,48,.12);}
.sizeBtn.on i{color:var(--accent);}
.addonList{display:flex;flex-direction:column;gap:8px;}
.addon{display:flex;align-items:center;gap:10px;padding:14px 16px;border-radius:14px;
  border:1.5px solid var(--glassBorder);background:linear-gradient(180deg,rgba(255,255,255,.08),rgba(255,255,255,0) 55%),var(--bg2);color:var(--ink);cursor:pointer;transition:.2s;font:inherit;}
.addon:hover{border-color:#3a3a46;}
.addonName{font-weight:600;font-size:14px;}
.addonPrice{margin-left:auto;color:var(--mut);font-size:13px;}
.addonCheck{width:26px;height:26px;border-radius:8px;background:#2a2a32;display:grid;place-items:center;color:var(--mut);transition:.2s;}
.addon.on{border-color:var(--blue);background:rgba(91,141,239,.12);}
.addon.on .addonPrice{color:var(--ink);}
.addon.on .addonCheck{background:var(--blue);color:#fff;}
.sheetBar{padding:14px 20px calc(14px + env(safe-area-inset-bottom));border-top:1px solid var(--glassBorder);background:rgba(16,28,44,0.6);backdrop-filter:blur(24px) saturate(160%);-webkit-backdrop-filter:blur(24px) saturate(160%);}
.addBig{width:100%;display:flex;align-items:center;justify-content:space-between;padding:17px 22px;border:none;
  border-radius:16px;background:var(--grad);color:#15151b;border:1px solid rgba(255,255,255,0.5);box-shadow:inset 0 2px 3px rgba(255,255,255,0.65),inset 0 -3px 6px rgba(150,100,0,0.32),0 8px 22px rgba(244,196,48,.5),0 2px 6px rgba(0,0,0,0.18);font:inherit;font-weight:700;font-size:16px;cursor:pointer;transition:.2s;}
.addBig:hover{filter:brightness(1.06);}
.addBig:active{transform:translateY(1px) scale(.98);box-shadow:inset 0 3px 8px rgba(0,0,0,.22),0 0 24px rgba(244,196,48,.6);}
.addBig:disabled{opacity:.4;cursor:default;}
.addBig b{font-family:inherit;letter-spacing:-0.02em;font-size:17px;}
/* ===== оформление заказа ===== */
.coBlock{margin-top:20px;}
.coLabel{font-size:13px;color:var(--mut);font-weight:600;margin-bottom:9px;}
.coTableShow{display:flex;align-items:center;gap:10px;flex-wrap:wrap;background:var(--bg2);border:1px solid var(--line);
  border-radius:15px;padding:14px 16px;}
.coTableNum{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:17px;color:var(--ink);}
.coTableHint{font-size:12px;color:var(--mut);flex:1;}
.coChange{border:none;background:transparent;color:var(--accent);font:inherit;font-weight:700;font-size:13px;cursor:pointer;}
.coTableEdit{display:flex;gap:8px;}
.coInput{flex:1;background:var(--bg2);border:1px solid var(--line);border-radius:13px;padding:13px 15px;
  color:var(--ink);font:inherit;font-size:16px;outline:none;}
.coInput:focus{border-color:var(--accent);}
.coMiniBtn{border:1px solid rgba(255,255,255,0.5);background:var(--grad);color:#15151b;font:inherit;font-weight:700;padding:0 18px;border-radius:13px;cursor:pointer;}
.payOpt{width:100%;display:flex;align-items:center;gap:13px;background:linear-gradient(180deg,rgba(255,255,255,.07),rgba(255,255,255,0) 55%),var(--bg2);border:1px solid var(--glassBorder);
  border-radius:15px;padding:14px 16px;margin-bottom:10px;cursor:pointer;transition:.18s;text-align:left;}
.payOpt:hover{border-color:#3a3a46;}
.payOpt.on{border-color:var(--accent);background:rgba(244,196,48,.08);}
.payIcon{width:42px;height:42px;border-radius:11px;background:var(--card);display:grid;place-items:center;color:var(--ink);flex:0 0 auto;}
.payTxt{display:flex;flex-direction:column;gap:2px;flex:1;}
.payTxt strong{font-size:14px;font-weight:700;color:var(--ink);}
.payTxt span{font-size:12px;color:var(--mut);}
.payDot{width:20px;height:20px;border-radius:50%;border:2px solid var(--line);flex:0 0 auto;transition:.18s;}
.payOpt.on .payDot{border-color:var(--accent);background:radial-gradient(circle,var(--accent) 0 42%,transparent 46%);}
.qrPay{display:flex;flex-direction:column;align-items:center;gap:12px;padding:18px 0 6px;}
.qrBox{background:#fff;border-radius:18px;padding:16px;}
.qrHint{font-size:13px;color:var(--mut);text-align:center;}
.coTextarea{width:100%;background:var(--bg2);border:1px solid var(--line);border-radius:14px;padding:13px 15px;
  color:var(--ink);font:inherit;font-size:14px;outline:none;resize:none;}
.coTextarea:focus{border-color:var(--accent);}
.coTextarea::placeholder{color:#5a5a66;}
/* успешный заказ */
.orderDone{display:flex;flex-direction:column;align-items:center;text-align:center;padding:54px 26px 30px;}
.doneCheck{width:90px;height:90px;border-radius:50%;background:rgba(52,149,80,.16);color:#3ba35b;
  display:grid;place-items:center;margin-bottom:20px;animation:popIn .4s cubic-bezier(.2,1.3,.4,1);}
@keyframes popIn{from{transform:scale(.4);opacity:0;}to{transform:scale(1);opacity:1;}}
.orderDone h2{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:24px;margin-bottom:6px;}
.doneNo{font-weight:700;color:var(--accent);font-size:15px;margin-bottom:14px;}
.doneTxt{font-size:14px;color:var(--mut);line-height:1.5;margin-bottom:18px;}
.doneEta{background:var(--bg2);border:1px solid var(--line);border-radius:100px;padding:10px 20px;
  font-size:13px;font-weight:600;color:var(--ink);margin-bottom:28px;}
.doneBtn{max-width:none;}
.doneBtn{justify-content:center;}
.cartCard .detailName{margin-top:14px;}
.cartRow{display:flex;align-items:center;gap:12px;padding:12px 0;border-bottom:1px solid var(--line);}
.cartThumb{width:54px;height:54px;border-radius:14px;overflow:hidden;position:relative;flex:0 0 auto;
  background:radial-gradient(circle at 50% 30%,#2a2a34,#131318);}
.cartThumb .art{transform:scale(.52);}
.cartInfo{display:flex;flex-direction:column;gap:2px;flex:1;min-width:0;}
.cartInfo strong{font-size:14px;font-weight:700;}
.cartInfo span{font-size:12px;color:var(--mut);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;}
.cartPrice{font-family:inherit;letter-spacing:-0.02em;font-size:14px;white-space:nowrap;}
.cartLinePrice{font-family:inherit;letter-spacing:-0.02em;font-size:13px;color:var(--ink);margin-top:2px;}
.cartRowRight{display:flex;flex-direction:column;align-items:flex-end;gap:8px;flex:0 0 auto;}
.cartDel{width:30px;height:30px;border-radius:9px;border:none;cursor:pointer;background:transparent;
  color:var(--mut);display:grid;place-items:center;transition:.18s;}
.cartDel:hover{color:#ff6b6b;background:rgba(255,107,107,.12);}
.cartStepper{padding:2px;}
.cartStepper .stepBtn{width:30px;height:30px;}
.cartStepper .stepNum{min-width:20px;font-size:14px;}
.cartSummary{margin-top:18px;padding-top:14px;border-top:1px solid var(--line);display:flex;flex-direction:column;gap:8px;}
.cartSummaryRow{display:flex;justify-content:space-between;font-size:14px;color:var(--mut);}
.cartSummaryRow.total{color:var(--ink);font-weight:700;font-size:17px;font-family:inherit;letter-spacing:-0.02em;}
.cartEmpty{display:flex;flex-direction:column;align-items:center;gap:8px;text-align:center;padding:50px 20px 40px;color:var(--mut);}
.cartEmptyIcon{width:84px;height:84px;border-radius:50%;display:grid;place-items:center;color:#4a4a56;
  background:var(--bg2);border:1px solid var(--line);margin-bottom:4px;}
.cartEmpty p{font-weight:700;font-size:17px;color:var(--ink);}
.cartEmpty span{font-size:13px;}
.clearBtn{margin-top:16px;width:100%;padding:13px;border-radius:14px;border:1px solid var(--line);
  background:transparent;color:var(--mut);font:inherit;font-weight:600;cursor:pointer;transition:.2s;}
.clearBtn:hover{color:#ff6b6b;border-color:#ff6b6b;}

/* ===== pager / горизонтальный scroll-snap между вкладками ===== */
.pager{position:relative;}
.track{display:flex;width:100%;overflow-x:auto;overflow-y:hidden;
  scroll-snap-type:x mandatory;-webkit-overflow-scrolling:touch;
  scrollbar-width:none;overscroll-behavior-x:contain;scroll-behavior:smooth;}
.track::-webkit-scrollbar{display:none;}
.page{flex:0 0 100%;min-width:100%;scroll-snap-align:start;scroll-snap-stop:always;}
.pageBody{padding:6px 16px 0;}
.subChips{display:flex;gap:8px;overflow-x:auto;scrollbar-width:none;padding:8px 0 14px;}
.subChips::-webkit-scrollbar{display:none;}
.subChip{flex:0 0 auto;padding:8px 16px;border-radius:100px;border:1px solid var(--line);
  background:var(--bg2);color:var(--mut);font:inherit;font-weight:600;font-size:13px;cursor:pointer;transition:.2s;}
.subChip:hover{color:var(--ink);border-color:#3a3a46;}
.subChip:active{transform:scale(.95);background:var(--card);}
.dots{position:fixed;left:50%;bottom:40px;transform:translateX(-50%);z-index:35;display:flex;gap:7px;
  padding:7px 12px;border-radius:100px;background:rgba(16,32,52,.7);backdrop-filter:blur(10px);border:1px solid var(--line);}
.dot{width:7px;height:7px;border-radius:50%;background:#3a3a46;cursor:pointer;transition:.25s;}
.dot.on{background:var(--accent);width:20px;border-radius:6px;}
.dotsHidden{opacity:0;pointer-events:none;}
.emptyTab{display:flex;flex-direction:column;align-items:center;gap:8px;text-align:center;
  padding:90px 24px;color:var(--mut);}
.emptyIcon{width:72px;height:72px;border-radius:50%;display:grid;place-items:center;color:#4a4a56;
  background:var(--bg2);border:1px solid var(--line);margin-bottom:6px;}
.emptyTab p{font-weight:700;font-size:16px;color:var(--ink);}
.emptyTab span{font-size:13px;max-width:240px;}

/* ===== hero showcase (крупная витрина продукта) ===== */
.heroShow{position:relative;height:78vh;min-height:480px;max-height:720px;overflow:hidden;cursor:pointer;
  background:radial-gradient(120% 80% at 50% 18%,#2c2c38,#101015 70%);}
.heroShowMedia{position:absolute;inset:0;display:grid;place-items:center;overflow:hidden;}
.heroShowMedia .art{transform:scale(2.2);transition:transform .6s cubic-bezier(.2,.8,.3,1);}
.heroShow:hover .heroShowMedia .art{transform:scale(2.32);}
.heroShowMedia .dishPhoto{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;object-position:center 42%;}
.heroShowShade{position:absolute;inset:0;pointer-events:none;
  background:linear-gradient(180deg,rgba(11,31,58,.55) 0%,rgba(11,31,58,0) 26%,rgba(11,31,58,0) 52%,rgba(11,31,58,.82) 88%,var(--bg) 100%);}
.heroTag{top:auto;left:20px;bottom:auto;}
.heroShow .heroTag{position:absolute;top:18px;left:18px;}
.heroShowInfo{position:absolute;left:0;right:0;bottom:0;z-index:3;padding:0 22px 38px;
  display:flex;flex-direction:column;align-items:center;text-align:center;gap:6px;
  animation:rise .7s cubic-bezier(.2,.9,.3,1) both;}
.heroShowInfo h2{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:30px;line-height:1.1;letter-spacing:-.5px;}
.heroShowPrice{font-family:inherit;letter-spacing:-0.02em;font-weight:700;font-size:20px;color:var(--ink);}
/* кнопка/счётчик в витрине-герое */
.heroAddBtn{margin-top:14px;display:inline-flex;align-items:center;gap:8px;padding:13px 26px;border:1px solid rgba(255,255,255,0.5);
  border-radius:100px;background:var(--grad);color:#15151b;font:inherit;font-weight:700;font-size:15px;
  cursor:pointer;transition:.18s;box-shadow:inset 0 2px 3px rgba(255,255,255,0.6),inset 0 -3px 6px rgba(150,100,0,0.3),0 8px 24px -6px rgba(244,196,48,.55);}
.heroAddBtn:hover{transform:scale(1.05);}
.heroAddBtn:active{transform:scale(.96);box-shadow:inset 0 3px 8px rgba(0,0,0,.22),0 0 24px rgba(244,196,48,.6);}
.heroStepper{margin-top:14px;background:rgba(16,32,52,.7);backdrop-filter:blur(10px);border-color:rgba(255,255,255,.18);}
.heroStepper .stepNum{font-size:17px;min-width:26px;}
.heroStepper .stepBtn{width:38px;height:38px;}
.heroShowPrice i{font-style:normal;color:var(--mut);font-size:14px;}
`}</style>);}
